import{_ as e,o as a,c as t,ak as _}from"./chunks/framework.BwREiRwV.js";const m=JSON.parse('{"title":"第十四章 山门警钟","description":"","frontmatter":{},"headers":[],"relativePath":"永恒道途/正文/第一卷-山门有路/第十四章-山门警钟.md","filePath":"永恒道途/正文/第一卷-山门有路/第十四章-山门警钟.md"}'),r={name:"永恒道途/正文/第一卷-山门有路/第十四章-山门警钟.md"};function o(n,p,s,c,i,d){return a(),t("div",null,[...p[0]||(p[0]=[_('<h1 id="第十四章-山门警钟" tabindex="-1">第十四章 山门警钟 <a class="header-anchor" href="#第十四章-山门警钟" aria-label="Permalink to &quot;第十四章 山门警钟&quot;">​</a></h1><p>西北山坳里，藏着一座废弃石寨。</p><p>寨墙塌了大半，门前破旗被夜风吹得啪啪作响。从外面看，那里像是猎户多年前留下的歇脚地，院中却堆着刚劈开的柴，东墙还挂着两张新剥兽皮。</p><p>陈玄伏在下风口的枯松后，先闻到一丝腥甜。</p><p>血骨香。</p><p>他没有继续靠近。</p><p>接下来两个时辰，陈玄沿石寨外围缓慢绕行。每走一段便停下来听，发现守寨之人共有四个：东门一人，屋后高台一人，正屋里有两道更强气息。</p><p>高台与东门每半个时辰换一次岗。正屋的人始终没有出来，只偶尔传出酒坛碰撞声。</p><p>炼气七层的血骨钩修士，多半就在里面。</p><p>陈玄现在是炼气六层，伤势却只恢复六成。青元剑气最多能稳定斩出两道，第二道之后，右臂经脉便可能重新裂开。</p><p>正面闯寨，与送死没有区别。</p><p>他没有因仇敌近在眼前便失去耐心，只把寨门、墙缺、柴堆与山道位置全部记住，随后原路退回暗河。</p><p>第一夜，只看。</p><p>第二日黄昏，陈玄换到南侧山脊。</p><p>守寨的四人有一人离开，直到深夜才背着两具妖兽尸体回来。换岗时，东门守卫抱怨搜山无果，高台上的人则说薛师兄准备两日后撤往红石谷。</p><p>两日。</p><p>陈玄若回宗报信，最快也要三日。等长老带人赶到，石寨只会剩下一地灰烬。</p><p>那名外出猎兽的守卫把尸体拖进西侧小棚。棚内堆着诱妖香、锁妖索和几个刻有青云宗标记的空药瓶，显然不只陆炳这一支队伍遭过毒手。</p><p>证据就在里面。</p><p>第二夜，仍旧只看。</p><p>第三日下起细雨。</p><p>雨水冲淡血骨香，也让石寨守卫比前两日松懈。午后，一名瘦削血魔弟子从正屋出来，带着高台守卫离寨，谈话中提到“先去红石谷见少主”。</p><p>寨内只剩两人。</p><p>炼气七层的薛姓修士，以及东门那个炼气五层守卫。</p><p>陈玄终于开始动手。</p><p>他先在南侧山路留下半串脚印。脚印深浅不一，像一个重伤之人跌跌撞撞经过，末端则丢着一截从自己血衣上割下的布条。</p><p>随后，他把乌鳞草粉撒进西侧兽棚，在棚外埋下一张引火符。雨水会压住普通火焰，却洗不掉乌鳞草粉里的油性。只要符火点燃，兽皮与诱妖香都会成为最好的燃料。</p><p>最后，陈玄在东墙缺口外布下一条细索。</p><p>那不是法器，只是普通麻绳，一端系在松根，另一端连着几块拳头大小的山石。炼气修士清醒时绝不会被它绊倒，可人在黑暗、浓烟和追敌时，看到的往往只有自己想抓住的东西。</p><p>夜色完全沉下后，陈玄故意从南坡踩断一根枯枝。</p><p>东门守卫立刻抬头。</p><p>“谁？”</p><p>陈玄没有回答，身影在林间一闪而没。</p><p>守卫追到脚印旁，看见染血布条，眼中顿时亮起贪色。他没有回寨叫人，只抽出短刀，循着脚印独自追入南坡。</p><p>脚印在一片乱石前消失。</p><p>守卫停下时，陈玄已经从他身后的树上落下。</p><p>青锋剑没有亮起剑气。</p><p>左手先捂住口鼻，右手短刀从下颌刺入。守卫身体猛地一僵，灵力刚从丹田提起，陈玄已经拧断他的脖颈。</p><p>整个过程不到两息。</p><p>陈玄把尸体拖进灌木，取走腰牌和衣袍。对方临死前睁大的眼睛没有让他迟疑。此人守在一座以同门性命为饵的石寨里，腰间还挂着三只青云宗储物袋。</p><p>该杀。</p><p>陈玄不会为该杀的人替自己寻找愧疚。</p><p>他换上血纹黑袍，把脸藏进兜帽，提着一只妖兽血袋回到东门。</p><p>正屋里的薛姓修士果然出声：“怎么去了这么久？”</p><p>陈玄压低嗓音：“南坡发现血迹，像是那小子的。”</p><p>屋内静了一瞬。</p><p>门被推开。</p><p>薛姓修士身材横壮，右臂缠着暗红血纹，手中那柄骨白短钩正是将陈玄逼入暗河的法器。他没有立刻走出，只站在门槛后打量黑袍下的身影。</p><p>“抬头。”</p><p>陈玄没有抬。</p><p>他把手中血袋向前一抛。</p><p>薛姓修士本能侧身，血袋在门框上炸开。浓重兽血泼满半边墙壁，也遮住他一瞬视线。</p><p>同一刻，陈玄引动西侧符纸。</p><p>轰！</p><p>兽棚火光冲天。诱妖香被火焰点燃，甜腻浓烟迅速卷过院落。薛姓修士惊怒转头，陈玄已经退出东门，故意让染血绷带从黑袍下露出一角。</p><p>“是你！”</p><p>血骨钩破开雨幕，擦着陈玄后颈飞过，又被一条血链拽回掌中。</p><p>薛姓修士冲出寨门，脸上先是难以置信，继而化为狞笑：“中了我的蚀脉血煞还能活，你身上果然有宝物。”</p><p>陈玄没有回应，只向东墙退。</p><p>“交出来，我可以让你死得痛快些。”</p><p>“你在谷口伏杀了多少青云弟子？”陈玄问。</p><p>“记不清了。”薛姓修士舔了舔唇边兽血，“炼气杂鱼，谁会数？”</p><p>这句话足够了。</p><p>陈玄转身便走。</p><p>薛姓修士最初仍防着埋伏，见他步子虚浮，后背伤处又渗出新血，眼中最后一丝谨慎逐渐被贪念压下。</p><p>“还想跑？”</p><p>血钩横扫，暗红煞气在雨中拉出一弯弧光。陈玄施展折云步侧移，仍被余劲擦中肋侧，刚愈合的断骨传来锐痛。</p><p>他没有回剑。</p><p>第一钩，退五步。</p><p>第二钩，护身灵光破碎。</p><p>第三钩落下时，他已经退到东墙缺口。</p><p>薛姓修士一步跨过碎墙，右脚正落在泥水中的细索上。麻绳被灵力当场扯断，却也带动侧方山石滚落。</p><p>他只偏头看了一眼。</p><p>陈玄等的就是这一眼。</p><p>青锋剑出鞘，第一道青元剑气贴着雨幕斩向咽喉。薛姓修士反应极快，血骨钩回挡，剑气与钩刃相撞，发出刺耳震鸣。</p><p>境界差距在这一刻显露无遗。</p><p>青元剑气只在骨钩上留下一道浅痕，陈玄却被反震逼退，右臂经脉像被撕开，鲜血立刻从袖口滴落。</p><p>“炼气六层？”薛姓修士先是一惊，旋即笑得更加贪婪，“七日破境，果然是大机缘！”</p><p>他运转血煞，右臂纹路一路爬上颈侧。钩影骤然快了一倍，院中雨水被切成大片白雾。</p><p>陈玄连挡三击。</p><p>第一击震裂虎口。</p><p>第二击划开左肩。</p><p>第三击将青锋剑荡出中门，血骨钩直奔心口。</p><p>陈玄来不及回剑，只能侧身。钩尖刺入胸前半寸，被肋骨卡住，血煞瞬间灌入伤口。</p><p>薛姓修士狞笑着向后一拉，想把他整个胸膛撕开。</p><p>陈玄却在此时弃剑，双手死死扣住血链。</p><p>“找死！”</p><p>血煞沿链侵入掌心，皮肤立刻泛起暗红。陈玄没有松手，反而借对方拉扯之力向前扑去。</p><p>两人的距离骤然缩到三尺。</p><p>薛姓修士看见他左手掌心多了一包黑粉。</p><p>乌鳞草、苦叶草与蛇涎果，被陈玄全部撒进近在咫尺的火光。</p><p>粉末爆开。</p><p>薛姓修士屏住呼吸，却没料到陈玄的目标不是口鼻。带着油性的药粉落在他爬满血纹的右臂上，被西侧飘来的火星瞬间引燃。</p><p>火焰顺血煞灵力倒卷。</p><p>薛姓修士惨叫一声，本能松开血链，拍向燃烧右臂。陈玄也为此付出代价，胸口血钩失去牵制，向外滑出时带下一片皮肉。</p><p>他没有去看伤口。</p><p>青锋剑还在三步外。</p><p>来不及捡。</p><p>陈玄并指成剑，将丹田剩余灵力尽数压向指尖。没有法器承载，这一击让整条右臂经脉同时胀痛，凝出的剑气也只有一尺。</p><p>一尺已经够了。</p><p>薛姓修士扑灭臂上火焰，抬头时，陈玄的两指已经点到他咽喉前。</p><p>青光一闪。</p><p>剑气穿喉而过。</p><p>薛姓修士身体僵住，眼中仍残留着惊怒与不信。他张嘴想说什么，血先从喉间涌出。手中的骨钩落入泥水，溅起一小片浑浊水花。</p><p>陈玄没有等他倒下，捡起青锋剑，又在心口补了一剑。</p><p>直到对方瞳孔彻底涣散，他才松开剑柄，单膝跪进雨地。</p><p>胸前伤口不断涌血，右臂已经抬不起来，丹田也几乎空了。</p><p>这一战，他赢在三日观察、火势、毒粉与对方的贪心。少任何一样，地上死的人都会换成他。</p><p>石寨火势越来越大。</p><p>陈玄服下止血散，强撑着回到西侧兽棚。那里堆着七只青云宗储物袋、三枚残破身份牌和一册猎杀记录。记录上没有名字，只有日期、人数与所得物资。最近一行写着：青云外门三人，二死一失，待寻。</p><p>二死。</p><p>陆炳和郑衡没有活下来。</p><p>陈玄看着那行字，沉默片刻，把猎杀册、身份牌与一枚血字铁令收入储物袋。</p><p>正屋暗格里还有一张残图。红石谷、黑风涧与另外两处山口被朱笔圈出，旁边写着不同日期。陈玄来不及细看，一并带走。</p><p>至于灵石、丹药与血道功法，他只取了不会留下追踪印记的十余块下品灵石。几瓶不明血丹与沾着人皮的册子全部留在火中。</p><p>他不修血道，也不会为了几件战利品把未知祸患带回宗门。</p><p>离寨前，陈玄搜过薛姓修士尸体。对方右腕内侧刻着一个“七”字，储物袋里有一封尚未送出的密信，开头只有四字。</p><p>“禀血魔子。”</p><p>血魔子。</p><p>陈玄第一次看见这个名字。</p><p>他把信封收入怀中，随后将薛姓修士与守卫尸体一同拖进燃烧正屋。火焰吞没黑袍，也吞没寨中浓得化不开的血腥气。</p><p>天亮之前，陈玄离开山坳。</p><p>他没有沿主路回宗，而是先向南绕出八十里，再从青云城方向折返。途中换过两次衣物，猎杀册与血字令分别藏在不同位置。直到确认没有追踪印记，才在第三日傍晚踏上青云宗山门石阶。</p><p>守门弟子第一眼几乎没有认出他。</p><p>灰衣破碎，左肩染血，胸口用布带缠了数层。脸色苍白得像一张纸，眼睛却仍清醒。</p><p>“药园陈玄，任务队伍遭血魔宗伏杀。”</p><p>他把陆炳与郑衡的身份牌放在石桌上。</p><p>“二人确认身亡。黑风山西北石寨已毁，另有猎杀记录、血字令与据点残图，请上报宗门。”</p><p>值守弟子不敢耽搁，立刻敲响示警铜钟。</p><p>韩执事赶到时，先看见两枚身份牌，脸色便沉了下去。等翻开那本猎杀册，他握册的手背青筋一根根绷起。</p><p>“据点是你毁的？”</p><p>“是。”</p><p>“里面几人？”</p><p>“初见四人。两人先行撤走，我杀了留守两人。”陈玄没有夸大，也没有隐去自己观察三日的经过，“其中一人炼气七层，使用血骨钩。弟子借火与药粉取胜，伤势不轻。”</p><p>韩执事看着他胸前渗出的血，半晌没有说话。</p><p>“为什么不先回宗？”</p><p>“来不及。两日后他们会撤。”</p><p>“你就不怕死在那里？”</p><p>“怕。”陈玄道，“所以先看了三日。”</p><p>韩执事似乎想骂，最后却只深深吐出一口气。他把猎杀册交给身旁执法弟子：“封锁任务殿消息，立即送刑律峰。残图另抄一份，原件送长老会。”</p><p>安排完，他看向陈玄：“你去药堂。没有命令，七日内不许离开宗门。”</p><p>“是。”</p><p>陈玄转身时，韩执事又叫住他。</p><p>“陆炳和郑衡的遗物，宗门会送给他们家人。猎杀记录里另外几名弟子，也会核查身份。”</p><p>陈玄停了一下：“多谢执事。”</p><p>他沿山道走向药堂。夕阳穿过云海，把远处山峰染成暗金色。路过的弟子看见他满身血污，纷纷让开，却不知道那只旧储物袋里装着多少人的死讯。</p><p>陈玄没有胜后的畅快。</p><p>该杀的人已经杀了，死去的人却不会因此回来。</p><p>这就是复仇真正的分量。</p><p>不是一句痛快，也不是火中一个背影，而是你亲手把仇人的命拿走后，仍要带着活人的伤和死者的名字继续向前。</p><p>药堂门前，鲁老头正拄着烟杆等他。</p><p>老人看见他，嘴唇动了动，最终只骂了一句：“还知道回来？”</p><p>陈玄勉强笑了笑：“欠你半块灵谷饼，总要还。”</p><p>鲁老头转过脸，抬手狠狠擦了一下眼角：“少废话。进去躺着。”</p><p>陈玄跨过门槛时，强撑三日的那口气终于松开。</p><p>黑暗涌来之前，他听见山门方向第二次响起警钟。</p><p>那不是为他。</p><p>是青云宗终于开始回应，黑风山里那些被悄无声息夺走的命。</p><p>（第十四章完）</p>',159)])])}const f=e(r,[["render",o]]);export{m as __pageData,f as default};
